<template>
    <view>
        <view class="container">
            <view class="memCount">
                <view class="mem1">
                    メンバー数
                </view>
                <view class="mem2">
                    <text>{{member}}</text>/{{allMember}}
                </view>
            </view>
            <view class="appointSet">
                <view>予約配信</view>
                <u-switch v-model="value" activeColor="#34C759"></u-switch>
            </view>
            <view class="date">
                <view class="fu">オフにすると、すぐにメッセージが配信されます</view>
                <view class="can">
                    <view class="canLeft">
                        <u-icon top="5" color="#aaa" name="calendar" size="34"></u-icon>
                    </view>
                    <view style="box-sizing: border-box;padding: 0 20upx;" @click="chooseDate">
                        {{date}} <text style="margin-left: 40upx;" @click.stop="chooseTime">{{time}}</text>
                    </view>
                </view>
            </view>
            <view class="title">
                配信ターゲット
            </view>
            <view class="chooseItem">
                <view class="item">
                    <view class="itemLeft">
                        <view class="unselect" @click="changeTab(0)" v-if="current == 1"></view>
                        <view class="selected" v-if="current == 0">
                            <view class="fill"></view>
                        </view>
                    </view>
                    <view class="itemRight" :style="current == 0? 'color:#1D1D1F;' : 'color: #AAAAAA' ">
                        すべて
                    </view>
                </view>
                <view class="item">
                    <view class="itemLeft">
                        <view class="unselect" @click="changeTab(1)" v-if="current == 0"></view>
                        <view class="selected" v-if="current == 1">
                            <view class="fill"></view>
                        </view>
                    </view>
                    <view class="itemRight" :style="current == 1? 'color:#1D1D1F;' : 'color: #AAAAAA' ">
                        絞り込み
                    </view>
                </view>
            </view>
            <view class="content" v-if="current == 1">
                <view class="contentItem" v-for="(item,index) in tabs" @click="toScene(index)">
                    <view class="tabLeft">
                        <view class="tabTop" v-text="item.name"></view>
                        <view class="tabBot" v-text="item.title"></view>
                    </view>
                    <view class="tabRight">
                        <image src="../../../static/icons/right.png" mode="aspectFit"></image>
                    </view>
                </view>
            </view>
            <u-button type="success" color="#34C759" @click="showMod" class="btn">メッセージを配信</u-button>
            <view class="blank"></view>
        </view>
        <u-calendar confirmText="完了" :show="showc" :closeOnClickOverlay='true' monthNum="36" :showTitle="false"
            @close="closeDate" @confirm="dateConfirm"></u-calendar>
        <u-datetime-picker :show="showd" :closeOnClickOverlay="true" v-model="value1" @confirm="pickerConfirm" mode="time" @close="closeTime">
        </u-datetime-picker>
        <mod v-if="showModule" @getStatus="getStatus" :config="configs"></mod>
        <aleOne v-if="show1" :number="allMember"></aleOne>
        <aleTwo v-if="show2" @confirm="buythis" @cancel="canThis" :number="allMember"></aleTwo>
    </view>
</template>
<script>
    import mod from "../../../components/mod.vue"
    import aleOne from "../../../components/alerts/you1/you1.vue"
    import aleTwo from "../../../components/alerts/you2/you2.vue"
    import {sceneMember,getMemberList,addCoupon,editCoupon,getExtra,payExtra} from '@/api/index.js'
    export default {
        components: {
            mod,
            aleOne,
            aleTwo
        },
        data() {
            return {
                current: 0,
                value: true,
                showd:false,
                show1: false,
                show2: false,
                showc: false,
                date:"",
                sdate:"",
                sDate:"",
                member:0,
                allMember:0,
                time:"00:00",
                value1: "",
                show: false,
                showModule: false,
                configs: {
                    title: 'クーポンを配信',
                    content: 'このクーポンは 今すぐ300人に送信されます。 配信しますか？',
                    cancel: true,
                    default: true,
                    cancelText: "配信",
                    defaultText: "キャンセル",
                    type: 'button'
                },
                tabs: [{
                        name: "誕生月",
                        title: "誕生月を設定"
                    },
                    {
                        name: "性別",
                        title: "性別を設定"
                    },
                    {
                        name: "来店期間",
                        title: "来店期間を設定"
                    },
                    {
                        name: "来店回数",
                        title: "来店回数を設定"
                    }
                ]
            }
        },
        
        onLoad(options) {
          let that = this
          let info = uni.getStorageSync("couponInfo")
          let config = uni.getStorageSync("scCoupon")
          let param = options.source
          that.query = options
          if(param == 'edit'){
              let times = config.order_time.split(" ")
              that.current = config.receiver
              that.date = times[0]
              that.sdate = times[0]
              that.time = times[1]
              console.log(that.current)
              if(that.current == 1){
                  console.log("created")
                  that.checkMemberCount()
              }else{
                  this.member = this.allMember 
              }
          }else{
             
              if(config.sendDate){
                  that.date = config.sendDate
              }else{
                  let date = new Date()
                  let fullDate
                  let year = date.getFullYear()
                  let month = date.getMonth() + 1 < 10 ? '0' + (date.getMonth() + 1) : date.getMonth() + 1
                  let day = date.getDate() < 10 ? "0" + (date.getDate()) : date.getDate()
                  let week = date.getDay() == 1 ? '月' : date.getDay() == 2 ? '火' : date.getDay() == 3 ? '水' : date.getDay() ==
                      4 ? '木' : date.getDay() == 5 ? '金' : date.getDay() == 6 ? '土' : '日'
                  fullDate = year + "-" + month + '-' + day + "(" + week + ")"
                  that.sDate = year + "-" + month + '-' + day
                  that.date = fullDate
                  that.sdate = year + "-" + month + '-' + day
                  console.log("alldate",fullDate)
              }
              
              if(config.sendTiem){
                  that.time = config.sendTiem
              }
          }
          
     
        },
        onShow() {
          if(this.current == 1){
              console.log("show")
              this.checkMemberCount()
          }else{
              this.member = this.allMember 
          }
          let that = this
          let data = {}
          data.page = 1
          data.page_size = 1
          data.keywords = ""
          data.sort = ""
          data.desc = ""
          getMemberList(data).then((res) => {
              if(res.code == 200){
                  that.allMember = res.data.total
                  that.member = res.data.total
              }
          })
        },
        methods: {
            showMod(){
              this.showModule = true  
              this.configs.content = "このクーポンは 今すぐ"+this.member+"人に送信されます。 配信しますか？"
            },
            changeTab(e) {
                this.current = e
                if(e == 0){
                    this.member = this.allMember
                }else{
                     this.checkMemberCount()
                }
            },
            buythis(e){
                console.log(e)
                let that = this
                let data = {}
                data['type'] = 2
                getExtra(data).then((res) => {
                    console.log(res)
                    if(res.code == 200){
                        let tem = {}
                        tem.order_no = res.data.order_no 
                        payExtra(tem).then((result) => {
                            if(result.code == 200 && result.data.url != ''){
                                setTimeout(function() {
                                    uni.navigateTo({
                                        url:"../../webview/webview?link="+res.data.url
                                    })
                                }, 500)
                            }else{
                                uni.showToast({
                                    title:result.message,
                                    icon: "none",
                                    duration:1500
                                })
                                that.show1 = false
                                that.show2 = false
                                // setTimeout(function() {
                                //     uni.switchTab({
                                //         url:"../../index/index"
                                //     })
                                // }, 1500)
                            }
                        })
                    }else{
                        uni.showToast({
                            title:res.message,
                            icon:"none"
                        })
                    }
                })
            },
            canThis(e){
                console.log(e)  
                this.show2 = false
            },
            chooseDate(e) {
                this.showc = true
            },
            closeDate() {
                this.show = false
            },
            chooseTime() {
                this.showd = true
            },
            closeTime() {
                this.showd = false
            },
            getStatus(e) {
                let that = this 
                if(e == "default"){
                    that.showModule = false
                }
                
                if(e == "cancel"){
                    let data = {}
                    let query = that.query.source
                    let id =  that.query.id
                    let config = uni.getStorageSync("scCoupon")
                    let info = uni.getStorageSync("couponInfo")
                    let birthday = ""
                    let sexStr = ''
                    if(config.birthday_month){
                        config.birthday_month.forEach((value,index) => {
                            if(index ==  config.birthday_month.length - 1){
                                birthday += value
                            }else{
                                birthday += value + ","
                            }
                        })
                    }else{
                        birthday = ""
                    }
                   
                    
                    if(config.sex){
                        config.sex.forEach((value,index) => {
                            if(index ==  config.sex.length - 1){
                                sexStr += value
                            }else{
                                sexStr += value + ","
                            }
                        })
                    }else{
                        sexStr = ""
                    }
                    
                    data.images = info.banner
                    data.title = info.title
                    data.number = info.number
                    data.is_indate = info.value == true? 1 : 0
                    data.indate_start_time = info.sDate
                    data.indate_end_time = info.eDate
                    data.is_bar_code = info.value3 == true? 1 : 0
                    data.count = info.value2 == true? info.count : 0
                    data.des = info.detail
                    data.remark = info.remark
                    data.is_order = that.value == true? 1 : 0
                    data.order_time = that.sdate + ' ' + that.time
                    data.receiver = that.current == 0? 1 : 2
                    data.birthday_month = birthday
                    data.sex = sexStr
                    data.shop_time = config.shop_time
                    data.shop_time_desc = config.shop_time_desc
                    data.shop_count = config.shop_count
                    data.shop_count_desc = config.shop_count_desc
                    
                    
                    if(query == "edit"){
                        data._method = "put"
                        editCoupon(data,id).then((res) => {
                            if(res.code == 200){
                                uni.showToast({
                                    title:res.message,
                                    duration:2000
                                })
                                uni.removeStorageSync("scCoupon")
                                uni.removeStorageSync("couponInfo")
                                setTimeout(function(){
                                    uni.redirectTo({
                                        url:"../coupon"
                                    })
                                },2000)
                            }else if(res.code == '4003'){
                                that.show2 = true
                            }else{
                                uni.showToast({
                                    title:res.message,
                                    icon:"none"
                                })
                            }
                        })
                    }else{
                        addCoupon(data).then((res) => {
                            if(res.code == 200){
                                uni.showToast({
                                    title:res.message,
                                    duration:2000
                                })
                                uni.removeStorageSync("scCoupon")
                                uni.removeStorageSync("couponInfo")
                                setTimeout(function(){
                                    uni.redirectTo({
                                        url:"../coupon"
                                    })
                                },2000)
                            }else if(res.code == "4003"){
                                that.show2 = true
                            }else{
                                uni.showToast({
                                    title:res.message,
                                    icon:"none"
                                })
                            }
                        })
                    }
                }
            },
            dateConfirm(e){
                let that = this
                that.show = false
                let date = new Date()
                let week = date.getDay()
                let wek
                if (week == 1) {
                    wek = "月"
                } else if (week == 2) {
                    wek = "火"
                } else if (week == 3) {
                    wek = "水"
                } else if (week == 4) {
                    wek = "木"
                } else if (week == 5) {
                    wek = "金"
                } else if (week == 6) {
                    wek = "土"
                } else if (week == 7) {
                    wek = "日"
                }
                that.date = e[0]+"("+wek+")"
                that.sdate = e[0]
            },
            
            pickerConfirm(e){ 
               let that = this
               that.time = e.value
            },
            toScene(e){
                let sceneCouponInfo = uni.getStorageSync("scCoupon")
                
                if(!sceneCouponInfo){
                    uni.setStorageSync("scCoupon",{"stype":1})
                }else{
                }
                
                
                if(e == 0){
                    uni.navigateTo({
                        url:"../setting/birthday/birthday"
                    })
                }else if(e == 1){
                    uni.navigateTo({
                        url:"../setting/sex/sex"
                    })
                }else if(e == 2){
                    uni.navigateTo({
                        url:"../setting/time/time"
                    })
                }else if(e == 3){
                    uni.navigateTo({
                        url:"../setting/times/times"
                    })
                }
            },
            
            checkMemberCount(){
                let that = this
                let config = uni.getStorageSync("scCoupon")
                let temp = [1,2,3]
                let aa = 1
                let data = {}
                data.birthday_month = config.birthday_month || []
                data.sex = config.sex || []
                data.shop_time = config.shop_time || ""
                data.shop_time_desc = config.shop_time_desc || 1
                data.shop_count = config.shop_count || ""
                data.shop_count_desc = config.shop_count_desc || 1
                sceneMember(data).then((res) => {
                    if(res.code == 200){
                        that.member = res.data.total
                        console.log(res.data.total)
                    }
                })
                
            }
        }
    }
</script>

<style lang="scss">
    .container {
        border-top: 2upx solid #D2D2D7;
        box-sizing: border-box;
        padding-top: 24upx;

        .cons {
            text-align: center;
        }

        .can {
            width: 100%;
            height: 80upx;
            border-radius: 20upx;
            display: flex;
            align-items: center;
            // justify-content: space-between;
            border: 2upx solid #aaa;
            overflow: hidden;
            margin: 34upx 0 60upx;

            .canLeft {
                background: #EAEAEA;
                text-align: center;
                border-right: 2upx solid #aaa;
                height: 100%;
                line-height: 80upx;
                width: 80upx;
                box-sizing: border-box;
                padding-left: 8upx;
            }
        }

        .fu {
            font-size: 24upx;
            font-family: Hiragino Sans-W3, Hiragino Sans;
            font-weight: normal;
            color: rgba(29, 29, 31, 0.9);
        }

        .appointSet {
            display: flex;
            align-items: center;
            justify-content: space-between;
            margin-top: 43upx;
            border-bottom: 2upx solid #d2d2d7;
            padding-bottom: 30upx;
        }

        .blank {
            width: 100%;
            height: 50upx;
        }

        .btn {
            width: 478upx;
            height: 96upx;
            background: rgba(29, 29, 31, 0.1);
            border-radius: 20upx;
            opacity: 1;
            border: 2upx solid #707070;
            font-size: 32upx;
            font-family: Hiragino Sans-W3, Hiragino Sans;
            font-weight: normal;
            color: #707070;
            margin-top: 144upx;
        }

        .content {
            border-left: 2upx solid #D2D2D7;
            border-right: 2upx solid #D2D2D7;
            border-top: 2upx solid #D2D2D7;
            margin: 32upx 0 0;
        }

        .contentItem {
            display: flex;
            align-items: center;
            justify-content: space-between;
            box-sizing: border-box;
            padding: 32upx;
            border-bottom: 2upx solid #D2D2D7;

            .tabLeft {
                .tabTop {
                    font-size: 32upx;
                    font-family: Hiragino Sans-W3, Hiragino Sans;
                    font-weight: normal;
                    color: #1D1D1F;
                    margin-bottom: 20upx;
                }

                .tabBot {
                    font-size: 32upx;
                    font-family: Hiragino Sans-W3, Hiragino Sans;
                    font-weight: normal;
                    color: #AAAAAA;
                }
            }

            .tabRight {
                image {
                    height: 46upx;
                    width: 23upx;
                }
            }
        }


        .item {
            display: flex;
            align-items: center;
            margin-top: 60upx;

            .itemLeft {
                margin-right: 28upx;
            }

            .unselect {
                width: 40upx;
                height: 40upx;
                background: #FFFFFF;
                opacity: 1;
                box-sizing: border-box;
                border: 2upx solid #707070;
                border-radius: 50%;
            }

            .selected {
                width: 40upx;
                height: 40upx;
                background: #FFFFFF;
                border: 2upx solid #1A73E8;
                border-radius: 50%;
                box-sizing: border-box;
                padding: 6upx;

                .fill {
                    width: 100%;
                    height: 100%;
                    background: #1A73E8;
                    border-radius: 50%;
                }
            }

        }

        .mem1 {
            font-size: 28upx;
            font-family: Hiragino Sans-W3, Hiragino Sans;
            font-weight: normal;
            color: #707070;
            text-align: right;
            margin-bottom: 14upx;
        }

        .mem2 {
            font-size: 32upx;
            font-family: Hiragino Sans-W3, Hiragino Sans;
            font-weight: normal;
            color: #707070;
            text-align: right;

            text {
                color: #1D1D1F;
            }
        }

        .title {
            font-size: 32upx;
            font-family: Hiragino Sans-W3, Hiragino Sans;
            font-weight: normal;
            color: #1D1D1F;
            margin-top: 40upx;
            border-bottom: 2upx solid #d2d2d7;
            padding-bottom: 22upx;
        }
    }
</style>
